args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?ruler ?rulerLabel ?title ?titleLabel WHERE {
  wd:Q330362 wdt:P580 ?commonwealthStart ;
             wdt:P582 ?commonwealthEnd .
  ?ruler wdt:P39 wd:Q512196 ;
         wdt:P580 ?termStart ;
         wdt:P582 ?termEnd .
  FILTER(?termStart >= ?commonwealthStart && ?termEnd <= ?commonwealthEnd)
  ?ruler rdfs:label ?rulerLabel .
  wd:Q512196 rdfs:label ?titleLabel .
  FILTER(LANG(?rulerLabel) = "en")
  FILTER(LANG(?titleLabel) = "en")
}
